import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life — nextGeneration", () => {
  it.todo("should return [] for empty input — empty grid stays empty");

  it.todo(
    "should kill a lone live cell — nextGeneration([[0,0]]) returns []"
  );

  it.todo(
    "should kill two adjacent live cells (underpopulation) — nextGeneration([[0,1],[1,1]]) returns []"
  );

  it.todo(
    "should leave a 2x2 block unchanged (still life) — nextGeneration([[0,0],[1,0],[0,1],[1,1]]) returns the same four cells"
  );

  it.todo(
    "should birth the diagonal-completing cell from an L-shape (reproduction) — nextGeneration([[0,0],[1,0],[0,1]]) returns the 2x2 block [[0,0],[1,0],[0,1],[1,1]]"
  );

  it.todo(
    "should kill the center of a full 3x3 from overpopulation — center (1,1) is absent from nextGeneration of all nine cells of the 3x3"
  );

  it.todo(
    "should oscillate a vertical blinker into a horizontal blinker — nextGeneration([[0,0],[0,1],[0,2]]) returns [[-1,1],[0,1],[1,1]]"
  );
});
